%%%%%%%%%% Function vrnLFNV01.m %%%%%%%%%%% Function Log File Name, ver.1% Kei Nakamura% Created on Wednesday, October 25th 2006.% Modified on %% function [scnAdr logNam] = vrnLFNV01(scnNmb)% returns the name of the log files% scnNmb: Scan number% scnAdr: address for scan% logNam% 1: 100tw log% 2: 100tw info file% 3: magnetic spc log% 4: spot logfunction [scnAdr logNam] = vrnLFNV01(scnNmb)  %function headerif scnNmb<10    scnAdr = strcat('Scan00',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan00',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan00',num2str(scnNmb),'.txt');    logNam{3} = strcat('scan',num2str(scnNmb),'mSpctLog.txt');    logNam{4} = strcat('scan',num2str(scnNmb),'spt.txt');elseif scnNmb<100    scnAdr = strcat('Scan0',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan0',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan0',num2str(scnNmb),'.txt');    logNam{3} = strcat('scan',num2str(scnNmb),'mSpctLog.txt');    logNam{4} = strcat('scan',num2str(scnNmb),'spt.txt');else    scnAdr = strcat('Scan',num2str(scnNmb));    logNam{1} = strcat('ScanDataScan',num2str(scnNmb),'.txt');    logNam{2} = strcat('ScanInfoScan',num2str(scnNmb),'.txt');    logNam{3} = strcat('scan',num2str(scnNmb),'mSpctLog.txt');    logNam{4} = strcat('scan',num2str(scnNmb),'spt.txt');end
